window.__QUIZ_DATA__=[{"id":"objective>Geography>2025>1","subject":"Geography","year":"2025","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Study the map of IJAMO DISTRICT and use it to answer the question below      The scale of the map in statement form is","images":["data:image/png;base64,"],"options":{"A":"one centimetre on the map represents half kilometre on the ground","B":"one centimetre on the map represents one kilometre on the ground","C":"one centimetre on the map represents two kilometres on the ground","D":"one centimetre on the map represents three kilometres on the ground"},"answer":"C","explanation":"The scale of the map in statement form is one centimetre on the map represents two kilometres on the ground","marks":"1","difficulty":"2"},{"id":"objective>Geography>2025>2","subject":"Geography","year":"2025","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Study the map of IJAMO DISTRICT and use it to answer the question below    What is the approximate bearing of Ebic from Oze?","images":["data:image/png;base64,"],"options":{"A":"320","B":"580","C":"3020","D":"3500"},"answer":"C","explanation":"Using the compass on the map. Bearings are measured clockwise from the North (00 or 3600). Ebic is northwest of Oze. From Oze to Ebic is approximately northwest which falls arround 3020.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2025>3","subject":"Geography","year":"2025","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"What will be the new scale of the map in Representative Fraction if the map is enlarged to twice its original size?","images":[],"options":{"A":"1: 100,000","B":"1: 200,000","C":"1: 300,000","D":"1: 400,000"},"answer":"A","explanation":"The new scale of the map in representative fraction if the map is enlarged to twice its original size is 1:100,000. Enlarged to twice its size means distances on paper double, so actual ground coverage becomes half.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2025>4","subject":"Geography","year":"2025","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"How many tributaries has River Momi?","images":[],"options":{"A":"5","B":"4","C":"2","D":"1"},"answer":"C","explanation":"Follow R.Momi on the map. It has 2 tributaries joining it:  a. one near the settlement \"Asebe\".  b. From north  Two joining rivers can be clearly traced to R.Momi","marks":"1","difficulty":"1"},{"id":"objective>Geography>2025>5","subject":"Geography","year":"2025","type":"Objective","topic":"REGIONAL GEOGRAPHY OF NIGERIA : SETTLEMENT","question":"What is the likely occupation of the people of IJAMO settlement?","images":[],"options":{"A":"Fishing","B":"Agriculture","C":"Mining","D":"Botany"},"answer":"B","explanation":"The likely occupation of the people of IJAMO settlement is Agriculture. Ijamo is surrounded by scattered cultivation and forest (checking the map legend and symbols) and there's no river or mining symbol nearby.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2025>6","subject":"Geography","year":"2025","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"The area of the map is approximately","images":[],"options":{"A":"1101 km2","B":"832 km2","C":"823 km2","D":"332 km2"},"answer":"A","explanation":"The area of the map is approximately:  map scale =1:200,000  This means 1cm=2km  If you measure the map((say approx. 21cm x 19.5cm)  =21 x 2=42Km(length)  =19.5 x 2  =39km width  Area =42 x 39  = 1638km2  None of the options match this exactly. But if the actual map dimention is smaller e.g 42 x 26km=1092km2 The closesoption is 1101km2","marks":"1","difficulty":"2"},{"id":"objective>Geography>2025>7","subject":"Geography","year":"2025","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"The distance in kilometres as the crow flie from Ofia to Yot is approximately","images":[],"options":{"A":"7 kilometres","B":"10 kilometres","C":"15 kilometres","D":"17 kilometres"},"answer":"C","explanation":"Direction of the migrating group from Ebic to Momi.  The distance in kilometres as the crow flies from Ofia to Yot is approximately 15km  map scale; 1:200000-1cm=2km  To measure the distance between Ofia and Yot on the map using ruler. The distance on the map is 7.5cm  Then 7.5cm x 2km/cm=15km","marks":"1","difficulty":"2"},{"id":"objective>Geography>2025>8","subject":"Geography","year":"2025","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : SETTLEMENT","question":"The second largest settlement on the mapped area is","images":[],"options":{"A":"IJAMO","B":"Oze","C":"Fada","D":"Asebe"},"answer":"B","explanation":"The second largest settlement on the mapped area is Oze","marks":"1","difficulty":"2"},{"id":"objective>Geography>2025>9","subject":"Geography","year":"2025","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : SETTLEMENT","question":"Ebic settlement is located in the","images":[],"options":{"A":"northern part of the mapped area","B":"western part of the mapped area","C":"southern part of the mapped area","D":"eastern part of the mapped area"},"answer":"D","explanation":"Ebic settlement is located in the north-eastern part of the map, but since 'northeastern' is not an option, the best fit direction is the Eastern. It is more close or it lies more to the east than to the north.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2025>10","subject":"Geography","year":"2025","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"The symbol 845 in the northeastern part of the mapped area is known as","images":[],"options":{"A":"hachure","B":"spot height","C":"benchmark","D":"valley"},"answer":"B","explanation":"The symbol *'845' represents a spot height, which shows the exact elevation of a specific point (in this case 845 metres) above sea level. The asterisk(*) indicates it's a spot height, not a contour line or trig point.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2025>11","subject":"Geography","year":"2025","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"The table below shows the temperature and rainfall distribution of Station Q.  Study and use it to answer the question  Station Q  MonthJan.Feb.Mar.April.May.June.July.Aug.Sept.Oct.Nov.Dec.Temperature (0C)212426323129272527272635Rainfall (mm)001113711212113021301200    What is the annual range of temperature for Station Q?","images":[],"options":{"A":"140C","B":"210C","C":"270C","D":"350C"},"answer":"A","explanation":"Annual range of Temperature=Highest monthly mean temp-lowest monthly mean temp  350-210  =140","marks":"1","difficulty":"2"},{"id":"objective>Geography>2025>12","subject":"Geography","year":"2025","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"The table below shows the temperature and rainfall distribution of Station Q.  Study and use it to answer the question  Station Q  MonthJan.Feb.Mar.April.May.June.July.Aug.Sept.Oct.Nov.Dec.Temperature (0C)212426323129272527272635Rainfall (mm)001113711212113021301200How many months of dry season has the station?","images":[],"options":{"A":"10","B":"5","C":"4","D":"2"},"answer":"C","explanation":"Loookingg at the table there was no rainfall for four months. Therefore there are four months of dry season in station Q.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2025>13","subject":"Geography","year":"2025","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"The table below shows the temperature and rainfall distribution of Station Q.  Study and use it to answer the question  Station Q  MonthJan.Feb.Mar.April.May.June.July.Aug.Sept.Oct.Nov.Dec.Temperature (0C)212426323129272527272635Rainfall (mm)001113711212113021301200The annual rainfall recorded at Station Q is","images":[],"options":{"A":"726 mm","B":"871 mm","C":"360 mm","D":"148 mm"},"answer":"B","explanation":"The annual rainfall recorded at Station Q is the summation of the rainfall in each month of the year at station Q.   The annual rainfall = 11 + 13 + 71 + 121 + 211 + 302 + 130 + 12=871mm","marks":"1","difficulty":"2"},{"id":"objective>Geography>2025>14","subject":"Geography","year":"2025","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Which of the following types of rainfall occurs when airmasses of different characteristics meet and their air mixes?","images":[],"options":{"A":"Conventional rainfall","B":"Relief rainfall","C":"Orographic rainfall","D":"Frontal rainfall"},"answer":"D","explanation":"Frontal rainfall happens when warm moist air meets cold dry air. The warm air, being lighter, rises over the cold air. As it rises, it cools, condenses, and forms clouds, leading to rainfall. This typically occurs att wheather fronts (either warm or cold fronts) especially in temperate regions.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2025>15","subject":"Geography","year":"2025","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Which coastal feature has the following characteristics?  I. Produced by wave erosion  II. Enlarges through alternate compression and expansion of air  III. Connects the top of the cliff to the sea  IV. Has narrow, chimney-like opening","images":[],"options":{"A":"Blow hole","B":"Tombolo","C":"Beach","D":"Spit"},"answer":"A","explanation":"I. Produced by wave erosion: Blowholes are formed by the erosive action of waves hitting weak points in sea cliffs  II. Enlarges through alternate compression and expansion of air: As waves crash into a sea cave, trapped air and water are compressed. When the pressure releases, it helps widen cracks and opeenings.  III. Connects the top of the cliff to the sea: A blowhole extends from a sea cave up to the top of a cliff allowing water and air to escape  IV. Has narrow, chimney-like opening: The vertical shaft is often narrow, causing water to shoot up like a greyser during high tides orr storms.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2025>16","subject":"Geography","year":"2025","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : VEGETATION","question":"The grass in the Savanna regions has adapted to the climate by","images":[],"options":{"A":"growing very short and in layers","B":"lying dormant during the long drought","C":"having shallow roots which spread near the surface","D":"having evergreen leaves"},"answer":"B","explanation":"Grasses in the savanna region survive the long dry season by going dormant, meaning they temporarily stop growing and turn brown to conserve wwater and energy. This is a key adaptation to the savanna's seasonal rainfall pattern-short wet season and long dry season.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2025>17","subject":"Geography","year":"2025","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"A line drawn on maps joining places of equal atmospheric pressure is called","images":[],"options":{"A":"isohaline","B":"isohyet","C":"isobar","D":"isoneph"},"answer":"C","explanation":"A line joining places of equal atmospheric pressure is called isobar.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2025>18","subject":"Geography","year":"2025","type":"Objective","topic":"THE SOLAR SYSTEM","question":"On the 22nd of December, the Sun is overhead at midday along the","images":[],"options":{"A":"Tropic of Cancer","B":"Aretic Circle","C":"Antarctic Circle","D":"Tropic of Capricom"},"answer":"D","explanation":"On the 22nd of December, the Sun is overhead at midday along the Tropic of Capricom","marks":"1","difficulty":"2"},{"id":"objective>Geography>2025>19","subject":"Geography","year":"2025","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"The temperature at the top of a mountain is 70C. What will be the temperature at the foot of the mountain if it is 5000 metres above sea level?","images":[],"options":{"A":"25.50C","B":"32.50C","C":"35.90C","D":"39.50C"},"answer":"D","explanation":"Lapse rate = 6.50C/1000m  Temperature rise = 6.5 x 5 = 32.50C  7 + 32.5 = 39.50C","marks":"1","difficulty":"2"},{"id":"objective>Geography>2025>20","subject":"Geography","year":"2025","type":"Objective","topic":"THE SOLAR SYSTEM","question":"On which of the following pairs of dates do solstices occur?","images":[],"options":{"A":"21st June and 22nd December","B":"21st March and 23rd December","C":"21st March and 21st June","D":"23rd September and 22nd December"},"answer":"A","explanation":"The pairs of dates 21st June and 22nd December is when solstices do occur","marks":"1","difficulty":"2"},{"id":"objective>Geography>2025>21","subject":"Geography","year":"2025","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Which of the following is a process of chemical weathering?","images":[],"options":{"A":"Block disintegration","B":"Hydrolysis","C":"Exfoliation","D":"Salt wedging"},"answer":"B","explanation":"The process of chemical weathering involves the alteration of the chemical composition of rocks and minerals. Hydrolysis is a key process in chemical weathering where water reacts with minerals to form new minerals and soluble salts. This is different from physical weathering processes like block disintegration, exfoliation, and salt wedging, which do not involve chemical changes.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2025>22","subject":"Geography","year":"2025","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : TECTONIC PROCESSES","question":"Rift valleys are landforms associated with","images":[],"options":{"A":"folding","B":"faulting","C":"vulcanicity","D":"residual mountain"},"answer":"B","explanation":"Rift valleys are landforms associated with faulting","marks":"1","difficulty":"2"},{"id":"objective>Geography>2025>23","subject":"Geography","year":"2025","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : DENUDATIONAL PROCESSES","question":"Which of the following pairs of landforms are produced by wind erosion in hot deserts?  I Zeugen  II Seif  III Yardang  IV Barchan","images":[],"options":{"A":"I and II only","B":"I and III only","C":"II and III only","D":"III and IV only"},"answer":"B","explanation":"Zeugen and Yardang are  pairs of landforms formed by wind erosion in hot deserts","marks":"1","difficulty":"2"},{"id":"objective>Geography>2025>24","subject":"Geography","year":"2025","type":"Objective","topic":"THE SOLAR SYSTEM","question":"A lunar eclipse occurs when the","images":[],"options":{"A":"sun comes between the earth and the moon","B":"moon comes between the sun and the stars","C":"earth comes between the sun and the moon","D":"sun misses its orbit"},"answer":"C","explanation":"A lunar eclipse occurs when the earth comes between the sun and the moon","marks":"1","difficulty":"1"},{"id":"objective>Geography>2025>25","subject":"Geography","year":"2025","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ENVIRONMENTAL PROBLEMS/ HAZARDS","question":"The most useeful function of the ozone layer in the atmosphere is to","images":[],"options":{"A":"prevent evaporation of water from the earth's surface","B":"absorb the carbon dioxide in the atmosphere","C":"absorrb ultraviolet radiation from the sun","D":"absorb water vapour from the atmosphere"},"answer":"C","explanation":"The most useeful function of the ozone layer in the atmosphere is to absorrb ultraviolet radiation from the sun.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2025>26","subject":"Geography","year":"2025","type":"Objective","topic":"THE SOLAR SYSTEM","question":"Which of the following is the correct sequence of the components of the internal structure of the earth?","images":[],"options":{"A":"Mantle, crust and core","B":"Crust, core and mantle","C":"Core, mantle and crust","D":"Mantle, core and crust"},"answer":"C","explanation":"The correct sequence of the components of the internal structure of the earth are Core, mantle and crust","marks":"1","difficulty":"3"},{"id":"objective>Geography>2025>27","subject":"Geography","year":"2025","type":"Objective","topic":"THE SOLAR SYSTEM","question":"The smallest and closest planet to the sun in the solar system is","images":[],"options":{"A":"Mars","B":"Mercury","C":"Venus","D":"Earth"},"answer":"B","explanation":"The smallest and closest planet to the sun in the solar system is mercury","marks":"1","difficulty":"1"},{"id":"objective>Geography>2025>28","subject":"Geography","year":"2025","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : GEOGRAPHIC INFORMATION SYSTEM (GIS)","question":"If someone in Town A located on longitude 1350E telephones a friend in Town B located on longitude 1200W at 10.00 am, at what time will his friend in Town B receive the call?","images":[],"options":{"A":"5:00 a.m","B":"5:00 p.m","C":"4:00 p.m","D":"4:00 a.m"},"answer":"B","explanation":"We calculate the time difference based on longitude:  Town A: 1350 East  Town B: 1200 West  Total longitude difference = 1350 + 1200  =2550  Since the earth rotates  150 per hour, 2550/15 =17 hours time difference.  Because Town A is ahead(fast), we substract this from 10:00am:  10:00am - 17hours = 5.00pm(previous day)","marks":"1","difficulty":"2"},{"id":"objective>Geography>2025>29","subject":"Geography","year":"2025","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : DENUDATIONAL PROCESSES","question":"A river's valley increases in length through the process of","images":[],"options":{"A":"sheet erosion","B":"vertical erosion","C":"lateral erosion","D":"headward erosion"},"answer":"D","explanation":"A river's valley increases in length through the process of headward erosion","marks":"1","difficulty":"2"},{"id":"objective>Geography>2025>30","subject":"Geography","year":"2025","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ROCKS","question":"Which of the followwing is an intrusive volcanic feature?","images":[],"options":{"A":"lopolith","B":"Lava cone","C":"Crater","D":"Composite cone"},"answer":"A","explanation":"A lopolith is a saucer-shaped intrusion. An intrusive volcanic feature forms beneath the earth's surface when magma cools and solidifies underground.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2025>31","subject":"Geography","year":"2025","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"A major characteristic of the Mediterranean climate is","images":[],"options":{"A":"annual range of temperature is more than 500C","B":"a concentration of rainfall in winter and a dry warm summer","C":"temperature range from 280C in summer to 170C iin winter","D":"annual rainfall is less than 250 mm."},"answer":"B","explanation":"The Mediterranean climate is known for:  wet winters   Hot, dry summers  Moderate overall rainfall(usually between 400-700mm annually)","marks":"1","difficulty":"2"},{"id":"objective>Geography>2025>32","subject":"Geography","year":"2025","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ROCKS","question":"The diagram below shows the interior view of a limestone cave.  Study and use it to answer the question       The landform marked X is","images":["data:image/png;base64,"],"options":{"A":"stalagmite","B":"grike","C":"clint","D":"stalactite"},"answer":"D","explanation":"Stalactite hang from the ceiling of limestone caves and form as mineral-rich water drips down. They are steep and pointed, forming vertically downward.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2025>33","subject":"Geography","year":"2025","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ROCKS","question":"Gabbro is an example of","images":[],"options":{"A":"metamorphic rock","B":"igneous rock","C":"sedimentary rock","D":"fossilized rock"},"answer":"B","explanation":"It forms beneath the earth's surface from the slow cooling of magma. It also has coarse-grained crystals.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2025>34","subject":"Geography","year":"2025","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : DENUDATIONAL PROCESSES","question":"The process by which strong winds lower the surface of deserts by lifting and blowing away of loose sand particles is known as","images":[],"options":{"A":"abrasion","B":"attrition","C":"traction","D":"deflation"},"answer":"D","explanation":"Deflation is the process where strong winds remove loose sand and dust from the surface, gradually lowering the ground level in deserts. It's a key agent of wind erosion in arid regions.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2025>35","subject":"Geography","year":"2025","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ENVIRONMENTAL PROBLEMS/ HAZARDS","question":"The introduction of harmful substances into the environment is known as environmental","images":[],"options":{"A":"polllution","B":"balance","C":"interaction","D":"intervention"},"answer":"A","explanation":"The introduction of harmful substances into the environment is known as environmental polllution.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2025>36","subject":"Geography","year":"2025","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : SETTLEMENT","question":"Which of the following is a function of urban settlements to rural settlements?","images":[],"options":{"A":"Unemployment","B":"Administration","C":"Food crop supply","D":"Trade deficit"},"answer":"B","explanation":"Urban settlements often function as administrative centres for rural areas, providing governance and public services.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2025>37","subject":"Geography","year":"2025","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRADE","question":"A major reason for low volume of trade among West African countries is","images":[],"options":{"A":"colonial ties","B":"differences in climate","C":"similarity of products","D":"political instability"},"answer":"C","explanation":"West Africa countries often produce similar goods(like agricuultural products or raw materials), which reduces the need for trade among themselves since there is less demand for what neighbours produce. The similarity limits intra-regional trade volume.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2025>38","subject":"Geography","year":"2025","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"Which of the following classes of industry uses raw materials from agriculture, mining and fishing?","images":[],"options":{"A":"Service industry","B":"Primary industry","C":"Secondary industry","D":"Tertiary industry"},"answer":"B","explanation":"Primary industry involves the extraction and collection of natural resources directly from the earth. They include agrriculture, mining, fishing and foresty.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2025>39","subject":"Geography","year":"2025","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRANSPORTATION","question":"One major reason for which air transportation is less patronized in Africa is due to the","images":[],"options":{"A":"limited number of airports in Africa","B":"discomfort of travelling by air","C":"high airline operation taxes","D":"expensive nature of travelling by air"},"answer":"D","explanation":"The high cost of air travel is the most significant reason many people in Africa(and other devveloping regions) do not patronize their transport.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2025>40","subject":"Geography","year":"2025","type":"Objective","topic":"REGIONAL GEOGRAPHY OF NIGERIA : POPULATION","question":"One of the most effective ways of solving the problem of over-population in any country is by","images":[],"options":{"A":"educating couples on the need to give birth to fewer children","B":"advising its citizens to emigrate to other countries and return to their home country a year later","C":"sensitizing its citizens to engage in agriculture","D":"discouraging rural-urban migration"},"answer":"A","explanation":"Overpopulation occurs when a country's population exceeds the resources and infrrastruucture available to support it.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2025>41","subject":"Geography","year":"2025","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : SETTLEMENT","question":"Farmsteads, hamlets, villages and towns are classification of settlements based on","images":[],"options":{"A":"function","B":"location","C":"size","D":"shape"},"answer":"C","explanation":"Seettlements likee farmssteads, hamlets, villages, and towns are classifieed based on their population size and physical extent.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2025>42","subject":"Geography","year":"2025","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"Which of the following pairs are reasons for establishing industries in urban centres?  I. Employment  II. Revenue generation  III. Religious tolerance  IV. Unemployment creation","images":[],"options":{"A":"I and II only","B":"II and IV only","C":"III and IV only","D":"I and IV only"},"answer":"A","explanation":"Industries are commonly establisheed in urrban centres for several reasons, among which the following are valid:  i. Employment: industries create job opportunities for the urban population  II. Revenue generation: Industries contribute to the economy by paying taxes and generating income","marks":"1","difficulty":"2"},{"id":"objective>Geography>2025>43","subject":"Geography","year":"2025","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRADE","question":"Which of the following type of goods is offered for sale at the global market by most developing countries?","images":[],"options":{"A":"Mining equipment","B":"Manufacturing goods","C":"Agricultural products","D":"Automobile"},"answer":"C","explanation":"Most developing countries participate in the global market primarily by exporting raw materials and agricultural products such as cocoa, coffee, cotton, tea, rubber, palm oil and tropical fruits. These countries often lack the industrial base needed to export high tech. or finished products like manfacturing goods, automobiles, or mining equipment, which are mostly exported by developed countries.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2025>44","subject":"Geography","year":"2025","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TOURISM","question":"The term resort is usually associated with","images":[],"options":{"A":"tourism","B":"commerce","C":"banking","D":"refugee"},"answer":"A","explanation":"The term resort is usually associated with tourism. A resort is a place people go for relaxation or recreation, typically associated with tourism.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2025>45","subject":"Geography","year":"2025","type":"Objective","topic":"REGIONAL GEOGRAPHY OF NIGERIA : ECOWAS","question":"The membership of the Economic Community of West African States (ECOWAS) consists of","images":[],"options":{"A":"12 countries","B":"13 countries","C":"15 countries","D":"16 countries"},"answer":"C","explanation":"The membership of the Economic Community of West African States (ECOWAS) consists of 15 countries.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2025>46","subject":"Geography","year":"2025","type":"Objective","topic":"REGIONAL GEOGRAPHY OF NIGERIA : POPULATION","question":"Calculate the number of persons per square kilometre if a given country has a population of 100 million and a total land area of 500,000km2","images":[],"options":{"A":"20 persons per square kilometre","B":"50 persons per square kilometre","C":"200 persons per square kilometre","D":"5,000 persons per square kilometre"},"answer":"C","explanation":"population = 100 million; land area = 500,000km2  Population density = 100,000,000/500000  =200 person per square kilometers","marks":"1","difficulty":"2"},{"id":"objective>Geography>2025>47","subject":"Geography","year":"2025","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"Which of the following is not a primary factor to be considered in the siting of industries in Tropical Africa?","images":[],"options":{"A":"Existence of tertiary education institutions","B":"Nearness to market","C":"Nearness to source of raw materials","D":"Government policy on industrialization"},"answer":"A","explanation":"Existence of tertiary education institutions. While education is important, It's not a primary factor. The others-market, raw materials and government policy directly influence siting decisions.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2025>48","subject":"Geography","year":"2025","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ENVIRONMENTAL RESOURCES","question":"Which of the following pairs are renewable source of energy?","images":[],"options":{"A":"Coal and nuclear","B":"Natural gas and diesel","C":"Hydro-power and solar","D":"Nuclear and natural gas"},"answer":"C","explanation":"Hydro-power and solar are both renewable sources of energy. The others are fossil or non-renewable sources.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2025>49","subject":"Geography","year":"2025","type":"Objective","topic":"REGIONAL GEOGRAPHY OF NIGERIA : AGRICULTURE","question":"Which of the following is not a characteristic of subsistence farming?","images":[],"options":{"A":"The produce is mainly for home consumption","B":"It is capital intensive","C":"Simple farm tools and methods are used","D":"It is labour intensive"},"answer":"B","explanation":"Subsistence farming is typically labour intensive and uses simple tools, not capital-intensive equipment.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2025>50","subject":"Geography","year":"2025","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"An example of heavy industry is","images":[],"options":{"A":"printing","B":"food processing","C":"household goods","D":"ship building"},"answer":"D","explanation":"Ship building requires large scale production and heavy machinery. It's a classic heavy industry.","marks":"1","difficulty":"1"}];